import base64

def encode_image(image_path: str) -> str:
    with open(image_path, "rb") as f:
        return base64.standard_b64encode(f.read()).decode("utf-8")

image_data = encode_image("screenshot.png")

response = client.chat.completions.create(
    model="gpt-4o",
    messages=[{
        "role": "user",
        "content": [
            {"type": "text", "text": "Describe this screenshot"},
            {"type": "image_url", "image_url": {
                "url": f"data:image/png;base64,{image_data}"
            }}
        ]
    }]
)

from tenacity import retry, stop_after_attempt, wait_exponential, retry_if_exception_type
from openai import RateLimitError, APIError

@retry(
    retry=retry_if_exception_type((RateLimitError, APIError)),
    wait=wait_exponential(multiplier=1, min=1, max=60),
    stop=stop_after_attempt(5)
)
def make_request(messages: list, model="gpt-4o-mini", temperature=0.2):
    response = client.chat.completions.create(
        model=model, messages=messages, temperature=temperature
    )
    return response.choices[0].message.content, response.usage

import tiktoken
def count_tokens(text: str, model: str = "gpt-4o") -> int: encoding = tiktoken.encoding_for_model(model) return len(encoding.encode(text))
usage = response.usage input_cost = usage.prompt_tokens * 2.50 / 1_000_000 # gpt-4o pricing output_cost = usage.completion_tokens * 10.00 / 1_000_000 print(f"Cost: ${input_cost + output_cost:.6f}")
